{!pc.useAltWater&&!pc.useBottled&&<><div style={cs.row}><span style={cs.rL}>{t.wTariff} ({calc.cur} {calc.wT}/m脙聝脗聜脙聜脗鲁)</span><span style={cs.rV}>{calcFmt(calc.mWC)} {calc.cur}/{isAr?"脙聝脗聵脙聜脗麓脙聝脗聶脙聜脗聡脙聝脗聵脙聜脗卤":"mo"}</span></div><div style={cs.row}><span style={cs.rL}>{t.dTariff} ({calc.cur} {calc.dT}/m脙聝脗聜脙聜脗鲁)</span><span style={cs.rV}>{calcFmt(calc.mDC)} {calc.cur}/{isAr?"脙聝脗聵脙聜脗麓脙聝脗聶脙聜脗聡脙聝脗聵脙聜脗卤":"mo"}</span></div></>}
