const Footer = ({setPage,setActiveProduct,lang}) => {const tx=T[lang].ft;const navTx=T[lang].nav;const prods=getProducts(lang);const isAr=lang==="ar";return(<footer style={{background:DARK,padding:"56px 24px 24px",borderTop:"3px solid "+AQUA,direction:isAr?"rtl":"ltr"}}><div style={{maxWidth:1200,margin:"0 auto"}}><div style={{display:"flex",justifyContent:"space-between",flexWrap:"wrap",gap:36,marginBottom:44}}><div style={{minWidth:220}}><Logo light height={32}/><p style={{fontSize:13,color:"rgba(255,255,255,0.4)",marginTop:14,maxWidth:280,lineHeight:1.65}}>{tx.desc}</p><div style={{marginTop:16,display:"flex",flexDirection:"column",gap:8}}><div style={{display:"flex",gap:8,alignItems:"center"}}><MailIcon/><span style={{fontSize:12,color:"rgba(255,255,255,0.5)"}}>admin@aquacube.info</span></div><div style={{display:"flex",gap:8,alignItems:"center"}}><PhoneIcon/><span style={{fontSize:12,color:"rgba(255,255,255,0.5)",direction:"ltr",unicodeBidi:"embed"}}>+962 79 150 79 49</span></div></div></div><div style={{display:"flex",gap:56,flexWrap:"wrap"}}><div><h4 style={{fontSize:11,fontWeight:600,color:"rgba(255,255,255,0.35)",textTransform:"uppercase",letterSpacing:2,marginBottom:16}}>{tx.pl}</h4>{prods.map(p=><div key={p.id} onClick={()=>{setActiveProduct(p.id);setPage("product-detail")}} style={{fontSize:13,color:"rgba(255,255,255,0.55)",marginBottom:10,cursor:"pointer"}}>{p.name}</div>)}</div><div><h4 style={{fontSize:11,fontWeight:600,color:"rgba(255,255,255,0.35)",textTransform:"uppercase",letterSpacing:2,marginBottom:16}}>{tx.cl}</h4>{[[navTx.products,"products"],[navTx.services,"services"],[navTx.calculator,"calculator"],[navTx.contact,"contact"]].map(([l,id])=><div key={id} onClick={()=>setPage(id)} style={{fontSize:13,color:"rgba(255,255,255,0.55)",marginBottom:10,cursor:"pointer"}}>{l}</div>)}</div></div></div><div style={{borderTop:"1px solid rgba(255,255,255,0.06)",paddingTop:20}}><p style={{fontSize:11,color:"rgba(255,255,255,0.25)",margin:0}}>{tx.cr}</p></div></div></footer>)};

const ScrollTop = () => {const[show,setShow]=useState(false);useEffect(()=>{const h=()=>setShow(window.scrollY>500);window.addEventListener("scroll",h);return()=>window.removeEventListener("scroll",h)},[]);if(!show)return null;return<button onClick={()=>window.scrollTo({top:0,behavior:"smooth"})} style={{position:"fixed",bottom:24,right:24,width:44,height:44,borderRadius:"50%",background:AQUA,border:"none",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 20px rgba(31,180,186,0.4)",zIndex:999}}><ArrowUpIcon/></button>};

export default function App(){const[page,setPage]=useState("home");const[activeProduct,setActiveProduct]=useState("greybox");const[lang,setLang]=useState("en");const[calcProduct,setCalcProduct]=useState(null);const solutionsRef=useRef(null);const navigate=(p)=>{if(p==="calculator"&&!calcProduct)setCalcProduct(null);setPage(p);window.scrollTo({top:0,behavior:"smooth"})};return(<div style={{fontFamily:lang==="ar"?"'Segoe UI','Tahoma','Arial',sans-serif":"system-ui,-apple-system,'Segoe UI',sans-serif",minHeight:"100vh",background:WHITE}}><style>{`*{box-sizing:border-box;margin:0}input:focus,textarea:focus{outline:none;border-color:${AQUA} !important}button{transition:opacity 0.2s}button:hover{opacity:0.9}::selection{background:${AQUA}30}@media(max-width:768px){.nav-desktop{display:none !important}.nav-mobile-btn{display:flex !important}.nav-mobile-menu{display:flex !important}}`}</style><Nav page={page} setPage={navigate} lang={lang} setLang={setLang}/>{page==="home"&&<><Hero setPage={navigate} solutionsRef={solutionsRef} lang={lang}/><ProductCards setPage={navigate} setActiveProduct={setActiveProduct} solutionsRef={solutionsRef} lang={lang}/><WhySection lang={lang}/><SectorsSection lang={lang}/><CTASection setPage={navigate} lang={lang}/></>}{page==="products"&&<ProductsHub setPage={navigate} setActiveProduct={setActiveProduct} lang={lang}/>}{page==="product-detail"&&<ProductDetail productId={activeProduct} setPage={navigate} setActiveProduct={setActiveProduct} setCalcProduct={setCalcProduct} lang={lang}/>}{page==="services"&&<ServicesPage setPage={navigate} lang={lang}/>}{page==="contact"&&<ContactPage lang={lang}/>}{page==="calculator"&&<CalculatorPage lang={lang} setPage={navigate} initialProduct={calcProduct}/>}<Footer setPage={navigate} setActiveProduct={setActiveProduct} lang={lang}/><ScrollTop/></div>)}
